function candidate(control, output, label, measure) {
  control.addEventListener("click", async function (event) {
    event.preventDefault();

    var buttons = Array.prototype.slice.call(document.querySelectorAll("button"));
    buttons.forEach(function (button) {
      button.disabled = true;
    });

    output.textContent = "";

    await new Promise(function (resolve) {
      requestAnimationFrame(resolve);
    });

    var result = await measure();

    buttons.forEach(function (button) {
      button.disabled = false;
    });

    var unit = result.unit;
    var samples = result.samples;
    var rowData = [
      ["samples", samples.length],
      ["total (" + unit + ")", result.total().toFixed(2)],
      ["mean (" + unit + ")", result.mean().toFixed(2)],
      ["standard deviation (" + unit + ")", result.standardDeviation().toFixed(2)]
    ];

    var table = document.createElement("table");
    var body = document.createElement("tbody");

    rowData.forEach(function (entry) {
      var row = document.createElement("tr");
      var nameCell = document.createElement("th");
      var valueCell = document.createElement("td");
      nameCell.textContent = entry[0];
      valueCell.textContent = entry[1];
      row.appendChild(nameCell);
      row.appendChild(valueCell);
      body.appendChild(row);
    });

    table.appendChild(body);
    output.appendChild(table);

    var environmentLabel = window.environmentLabel;
    var mappingCount = window.mappings.length;
    var exportBox = document.createElement("textarea");
    exportBox.value = samples.map(function (sample) {
      return [environmentLabel, mappingCount, label, sample].join("\t");
    }).join("\n");
    output.appendChild(exportBox);
  });
}
